function calcOutGivenIn(
    uint tokenBalanceIn,
    uint tokenWeightIn,
    uint tokenBalanceOut,
    uint tokenWeightOut,
    uint tokenAmountIn,
    uint swapFee
)
    internal pure
    returns (uint tokenAmountOut)
{
    uint weightRatio = bdiv(tokenWeightIn, tokenWeightOut);
    uint adjustedIn = bsub(BONE, swapFee);
    adjustedIn = bmul(tokenAmountIn, adjustedIn);
    uint y = bdiv(tokenBalanceIn, badd(tokenBalanceIn, adjustedIn));
    if (y == 0) {
        return 0;
    }
    uint foo = bpow(y, weightRatio);
    uint bar = bsub(BONE, foo);
    tokenAmountOut = bmul(tokenBalanceOut, bar);
    return tokenAmountOut;
}

function calcInGivenOut(
    uint tokenBalanceIn,
    uint tokenWeightIn,
    uint tokenBalanceOut,
    uint tokenWeightOut,
    uint tokenAmountOut,
    uint swapFee
)
    internal pure
    returns (uint tokenAmountIn)
{
    uint weightRatio = bdiv(tokenWeightOut, tokenWeightIn);
    uint diff = bsub(tokenBalanceOut, tokenAmountOut);
    uint y = bdiv(tokenBalanceOut, diff);
    if (y == 0) {
        return 0;
    }
    uint foo = bpow(y, weightRatio);
    foo = bsub(foo, BONE);
    tokenAmountIn = bsub(BONE, swapFee);
    tokenAmountIn = bdiv(bmul(tokenBalanceIn, foo), tokenAmountIn);
    return tokenAmountIn;
}

function completeSignerAuthorization(address account, bytes32 role) public {
  require(
    isAccount(account),
    "Unknown Account: Address that authorized signing must be a registered Account"
  );
  require(
    isNotAccount(msg.sender) && isNotAuthorizedSignerForAnotherAccount(account, msg.sender),
    "Cannot re-authorize address signer"
  );
  require(
    signerAuthorizations[account][role][msg.sender].started == true,
    "Signer authorization not started"
  );

  authorizedBy[msg.sender] = account;
  signerAuthorizations[account][role][msg.sender].completed = true;
  emit SignerAuthorizationCompleted(account, msg.sender, role);
}

function buy(
  uint256 buyAmount,
  uint256 maxSellAmount,
  bool buyGold
) external onlyWhenNotFrozen updateBucketsIfNecessary nonReentrant returns (uint256) {
  bool sellGold = !buyGold;
  (uint256 buyTokenBucket, uint256 sellTokenBucket) = _getBuyAndSellBuckets(sellGold);
  uint256 sellAmount = _getSellTokenAmount(buyTokenBucket, sellTokenBucket, buyAmount);

  require(
    sellAmount <= maxSellAmount,
    "Calculated sellAmount was greater than specified maxSellAmount"
  );

  _exchange(sellAmount, buyAmount, sellGold);
  return sellAmount;
}

function createCloneToken(
    string _cloneTokenName,
    uint8 _cloneDecimalUnits,
    string _cloneTokenSymbol,
    uint _snapshotBlock,
    bool _transfersEnabled
) public returns(MiniMeToken)
{
    uint256 snapshot = _snapshotBlock == 0 ? block.number - 1 : _snapshotBlock;

    MiniMeToken cloneToken = tokenFactory.createCloneToken(
        this,
        snapshot,
        _cloneTokenName,
        _cloneDecimalUnits,
        _cloneTokenSymbol,
        _transfersEnabled
    );

    cloneToken.changeController(msg.sender);

    // An event to make the token easy to find on the blockchain
    NewCloneToken(address(cloneToken), snapshot);
    return cloneToken;
}

function initiateModifyTimelockInterval(
  bytes4 functionSelector, uint256 newTimelockInterval, uint256 extraTime
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Ensure a timelock interval over eight weeks is not set on this function.
  if (functionSelector == this.modifyTimelockInterval.selector) {
    require(
      newTimelockInterval <= 8 weeks,
      "Timelock interval of modifyTimelockInterval cannot exceed eight weeks."
    );
  }

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.modifyTimelockInterval.selector,
    abi.encode(functionSelector, newTimelockInterval),
    extraTime
  );
}

function getTimelock(
  bytes4 functionSelector, bytes memory arguments
) public view returns (
  bool exists,
  bool completed,
  bool expired,
  uint256 completionTime,
  uint256 expirationTime
) {
  // Get timelock ID using the supplied function arguments.
  bytes32 timelockID = keccak256(abi.encodePacked(arguments));

  // Get information on the current timelock, if one exists.
  completionTime = uint256(_timelocks[functionSelector][timelockID].complete);
  exists = completionTime != 0;
  expirationTime = uint256(_timelocks[functionSelector][timelockID].expires);
  completed = exists && now > completionTime;
  expired = exists && now > expirationTime;
}

function parseRR(
    bytes memory data,
    uint256 idx,
    uint256 lastIdx
) internal view returns (address, bytes memory) {
    bytes memory txt = readTXT(data, idx, lastIdx);

    // Must start with the magic word
    if (txt.length < 5 || !txt.equals(0, "ENS1 ", 0, 5)) {
        return (address(0), "");
    }

    // Parse the name or address
    uint256 lastTxtIdx = txt.find(5, txt.length - 5, " ");
    if (lastTxtIdx > txt.length) {
        address dnsResolver = parseAndResolve(txt, 5, txt.length);
        return (dnsResolver, "");
    } else {
        address dnsResolver = parseAndResolve(txt, 5, lastTxtIdx);
        return (
            dnsResolver,
            txt.substring(lastTxtIdx + 1, txt.length - lastTxtIdx - 1)
        );
    }
}

function renewAll(
    string[] calldata names,
    uint256 duration,
    bytes32 referrer
) external payable override {
    ETHRegistrarController controller = getController();
    uint256 length = names.length;
    uint256 total;
    for (uint256 i = 0; i < length; ) {
        IPriceOracle.Price memory price = controller.rentPrice(
            names[i],
            duration
        );
        uint256 totalPrice = price.base + price.premium;
        controller.renew{value: totalPrice}(names[i], duration, referrer);
        unchecked {
            ++i;
            total += totalPrice;
        }
    }
    // Send any excess funds back
    payable(msg.sender).transfer(address(this).balance);
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata _executionCallData,
    bytes32,
    address,
    address
)
    public
    pure
    override
    onlySingleCallTypeMode(_mode)
    onlyDefaultExecutionMode(_mode)
{
    (address target_,,) = _executionCallData.decodeSingle();

    address[] memory allowedTargets_ = getTermsInfo(_terms);
    uint256 allowedTargetsLength_ = allowedTargets_.length;
    for (uint256 i = 0; i < allowedTargetsLength_; ++i) {
        if (target_ == allowedTargets_[i]) {
            return;
        }
    }
    revert("AllowedTargetsEnforcer:target-address-not-allowed");
}

function setReferralLink(uint256 tokenId, string calldata referralLink) public onlyRouter override {

    require(bytes(referralLink).length > 0, "Referral link can't be empty");

    bytes32 newReferral = keccak256(abi.encodePacked(referralLink));
    require(referralLinks[newReferral] == 0, "Referral link already used");

    delete referralLinks[keccak256(abi.encodePacked(referralStrings[tokenId]))];

    string memory oldReferralLink = referralStrings[tokenId];

    //Set referral link for NFT
    referralLinks[newReferral] = tokenId;
    referralStrings[tokenId] = referralLink;

    emit ReferralLinkChanged(tokenId, oldReferralLink, referralLink);
}
